#include <iostream>
#include <string>

class Animal {
public:
    virtual void print(std::ostream& out) const { out << "Animal"; }
    virtual ~Animal() = default;
    friend std::ostream& operator<<(std::ostream& out, const Animal& a) {
        a.print(out);
        return out;
    }
};

class Dog : public Animal {
    std::string name_;
public:
    Dog(const std::string& name) : name_(name) {}
    void print(std::ostream& out) const override { out << "Dog: " << name_; }
};

class Cat : public Animal {
    std::string name_;
public:
    Cat(const std::string& name) : name_(name) {}
    void print(std::ostream& out) const override { out << "Cat: " << name_; }
};

int main() {
    Animal a;
    Dog d{"Rex"};
    Cat c{"Whiskers"};
    Animal* arr[3] = {&a, &d, &c};
    for (int i = 0; i < 3; ++i)
        std::cout << *arr[i] << "\n";
    return 0;
}

